final:
module RefModule(
    input wire clk,
    input wire load,
    input wire [7:0] data_in,
    output reg [7:0] data_out
    );
  wire _tap_clk = clk & {1{1'b1}};


always @(posedge clk) begin
    if (load)
        data_out <= data_in;
    else
        data_out <= data_out >> 1;
end

endmodule
